sys_script_include.script:
/**
 * PLEASE NOTE: TaniumTDSUtil is in maintenance mode. It is not being actively developed,
 *  and will not be updated to support new features.
 * It is strongly recommended that you use the GatewayQueryUtil Script Include instead.
 **/
var TaniumTDSUtil = Class.create();
TaniumTDSUtil.prototype = Object.extendsObject(x_taniu_tan_core.TaniumIntegrationCore, {

	/**
	 * Checks that a TDS question has been constructed (using .addSensor() and
	 *  optionally, .addFilter()), and is ready to be asked. After verifying that
	 *  it's ready, sends the question to Tanium TDS, and returns the response
	 *  object from the Tanium TDS API.
	 * @return {boolean|Object|boolean|string}
	 * @example
	 * var endpointSerial = 'some_serial_number';
	 * var tdsUtil = new x_taniu_tan_core.TaniumTDSUtil();
	 *
	 * tdsUtil.addSensor('Computer ID');
	 * tdsUtil.addFilter('Computer Serial Number', 'Equals', endpointSerial);
	 * gs.info(JSON.stringify(
	 *    tdsUtil.askQuestion(),
	 *    null, 2
	 * ));
	 */
	askQuestion : function () {
		if (!this.tds_question) { this.tds_question = new this._TDS_Question(this.tds_response_row_count); }

		var rAskQuestionTDS, responseBody;

		if (!this.readyToSend()) {
			gs.error('Unable to ask question via TDS, as validation failed. Check your error logs for more details.');
			return false;
		}

		rAskQuestionTDS = this._getRESTObject(
			'Tanium Integration Core',
			'TDS-Ask Question'
		);

		rAskQuestionTDS.setStringParameterNoEscape(
			'tanium_module_api_url',
			this.TANIUM_MODULE_API_ENDPOINT
		);
		rAskQuestionTDS.setStringParameterNoEscape(
			'tds_question_body',
			JSON.stringify(this.tds_question.getQuestionObj())
		);

		responseBody = this._executeRESTCall(rAskQuestionTDS);

		return responseBody;
	},

	/**
	 *
	 * @param {String} sensorName - The exact name of a Tanium sensor to return the value(s)
	 *     of.
	 * @param {boolean} [flattenResults=true] - Whether to flatten the results
	 * @param {boolean} [groupResults=true] - Whether to group the results of the sensor.
	 * @param {string} [filterOp=] - If using a filter on this sensor, specify the filter
	 *  operation (such as "Equals").
	 * This param is only required if you want to add a filter <strong>to this sensor</strong>.
	 *     This is not the same as <strong>filtering the results of this question</strong>. For
	 *     that, use the .addFilter() method of this Script Include or Class.
	 * @param {string} [filterValue=] - If using a filter on this sensor, specify the value
	 *     you're filtering for using the operation in the filterOp parameter.
	 * This param is only required if you want to add a filter <strong>to this sensor</strong>.
	 *     This is not the same as <strong>filtering the results of this question</strong>. For
	 *     that, use the .addFilter() method of this Script Include or Class.
	 * @returns {this._Question}
	 * @example
	 * var endpointSerial = 'some_serial_number';
	 * var tdsUtil = new x_taniu_tan_core.TaniumTDSUtil();
	 *
	 * tdsUtil.addSensor('Computer ID');
	 * tdsUtil.addFilter('Computer Serial Number', 'Equals', endpointSerial);
	 * gs.info(JSON.stringify(
	 *    tdsUtil.askQuestion(),
	 *    null, 2
	 * ));
	 */
	addSensor : function (
		sensorName,
		flattenResults,
		groupResults,
		filterOp,
		filterValue
	) {
		if (!this.tds_question) { this.tds_question = new this._TDS_Question(this.tds_response_row_count); }

		this.tds_question.addSensor(sensorName, flattenResults, groupResults, filterOp, filterValue);


		return this;
	},

	/**
	 * Add a question-level filter. Any endpoints which do not match this filter will
	 *  not be shown in the results of this question.
	 * @param {string} sensorName
	 * @param {string} op
	 * @param {string} filterValue
	 * @return {TaniumTDSUtil}
	 * @example
	 * var endpointSerial = 'some_serial_number';
	 * var tdsUtil = new x_taniu_tan_core.TaniumTDSUtil();
	 *
	 * tdsUtil.addSensor('Computer ID');
	 * tdsUtil.addFilter('Computer Serial Number', 'Equals', endpointSerial);
	 * gs.info(JSON.stringify(
	 *    tdsUtil.askQuestion(),
	 *    null, 2
	 * ));
	 */
	addFilter : function (sensorName, op, filterValue) {
		if (!this.tds_question) { this.tds_question = new this._TDS_Question(this.tds_response_row_count); }
		this.tds_question.addFilter(sensorName, op, filterValue);
		return this;
	},

	/**
	 * Retrieve the TDS question object that will be sent to TDS when the .tds_askQuestion() method is called, as it's currently built.
	 * This is not a necessary step for asking a question via TDS, but can be useful for troubleshooting.
	 * @return {*}
	 */
	getQuestionObj : function () {
		if (!this.tds_question) { this.tds_question = new this._TDS_Question(this.tds_response_row_count); }
		return this.tds_question.getQuestionObj();
	},

	/**
	 * Checks whether a specific sensor (specified as the argument to this method) is
	 *  harvested for TDS (and thus able to be used in TDS question sensors and filters).
	 * @param {string} sensorName - The exact name of the sensor to check.
	 * @return {boolean}
	 * @example
	 * var tdsUtil = new x_taniu_tan_core.TaniumTDSUtil();
	 * gs.info(tdsUtil.isSensorHarvested('Computer Serial Number')); //true
	 */
	isSensorHarvested : function (sensorName) {
		if (!this.tds_question) { this.tds_question = new this._TDS_Question(this.tds_response_row_count); }
		var harvestedSensors = this.getAllHarvestedSensorNames();
		return (harvestedSensors.indexOf(sensorName) >= 0);
	},

	/**
	 * Get an array of the names of all TDS-harvested sensors.
	 * @return {boolean|*[]} - An array of the names of all TDS-harvested sensors.
	 * Returns boolean false if an error has occurred.
	 */
	getAllHarvestedSensorNames : function () {
		var i, harvestedSensorArray, harvestedSensor, responseBody;
		var harvestedSensorNames = [];
		var rHarvestedSensors = this._getRESTObject(
			'Tanium Integration Core',
			'TDS-Get Harvested Sensors'
		);

		rHarvestedSensors.setStringParameterNoEscape('tanium_module_api_url', this.TANIUM_MODULE_API_ENDPOINT);

		responseBody = this._executeRESTCall(rHarvestedSensors);

		if (!responseBody.hasOwnProperty('config') || responseBody.config.length < 1) {
			gs.error('Harvested sensor API response body did not contain a valid "config" ' +
				'property. This could indicate that TDS is not configured, that no sensors are ' +
				'being harvested, or that something went wrong with the request. Please check ' +
				'with your administrator.');
			return false;
		}

		harvestedSensorArray = responseBody.config;

		for (i = 0; i < harvestedSensorArray.length; i++) {
			harvestedSensor = harvestedSensorArray[i];
			if (harvestedSensor.active && harvestedSensor.name) {
				if (harvestedSensorNames.indexOf(harvestedSensor.name) < 0) {
					harvestedSensorNames.push(harvestedSensor.name);
				}
			}
		}

		return harvestedSensorNames;
	},

	/**
	 * @return {boolean} - True if the question object and current state indicates that
	 *  we're ready to send the question, or false if something's wrong.
	 */
	readyToSend : function () {
		if (!this.tds_question) { this.tds_question = new this._TDS_Question(this.tds_response_row_count); }
		//First validate the question object
		if (!this._validateQuestionObject()) {
			return false;
		}

		//Next, validate that we have the necessary properties and that they're valid.
		if (!this.TANIUM_MODULE_API_ENDPOINT) {
			gs.error('Tanium TDS API Endpoint not set. Please set the ' +
				'"x_taniu_tan_core.Tanium Integration Core.tanium_module_api_url" system property.');
			return false;
		}

		if (!this.session_id) {
			gs.error('Tanium session ID not set. Login may have failed on initialization of the ' +
				'TaniumTDSUtil Script Include. \nInitialization and login is performed by the ' +
				'extended SI, TaniumQuestion, and relies on several system properties and the ' +
				'proper endpoint and username/password being set.');
			return false;
		}

		return true;
	},

	/**
	 * @return {boolean} - True if question object is valid, false if not.
	 * @private
	 */
	_validateQuestionObject : function () {
		if (!this.tds_question) { this.tds_question = new this._TDS_Question(this.tds_response_row_count); }
		var i, questionSelectObj;
		var currentQuestion = this.getQuestionObj();

		//If question object does not have a select statement or select is empty, bail.
		if (!currentQuestion.hasOwnProperty('select') || currentQuestion.select.length < 1) {
			gs.error('When attempting to validate the Tanium TDS question object, found ' +
				'either no, or an empty, select statement. Question object is invalid.');
			return false;
		}

		//Iterate through and validate all sensors.
		for (i = 0; i < currentQuestion.select.length; i++) {
			questionSelectObj = currentQuestion.select[i];

			if (!questionSelectObj.hasOwnProperty('sensor')) {
				gs.error('When attempting to validate TDS question object in TaniumTDSUtil ' +
					'Script Include, "sensor" object was not found in the question object. ' +
					'This could be due to an internal error, but is more likely caused by a ' +
					'sensor not having been added using the .addSensor() method.');
				return false;
			}

			if (!questionSelectObj.sensor.hasOwnProperty('name')) {
				gs.error('When attempting to validate TDS question object in TaniumTDSUtil ' +
					'Script Include, sensor\'s "name" object was not found in the question ' +
					'object. This could be due to an internal error, but is more likely caused ' +
					'by a sensor name not having been added using the .addSensor() method.');
				return false;
			}

			//If filter_values node exists, BUT it has a missing "op" or "value" property, bail.
			if (questionSelectObj.hasOwnProperty('filter_values') && (
				!questionSelectObj.filter_values.hasOwnProperty('op') ||
				!questionSelectObj.filter_values.hasOwnProperty('value')
			)) {
				gs.error('TaniumTDSUtil Script Include: Question object\'s "filter_values" ' +
					'object is missing or invalid. It may be missing entirely, or may be ' +
					'missing the "op" or "value" child properties. This may be due to an ' +
					'internal error, but is more likely caused by an invalid .addSensor() call.');
				return false;
			}
		}

		//If all validations pass, return true.
		return true;
	},

	/**
	 * @return {*[]}
	 * @private
	 */
	_getAllUsedSensors : function () {
		if (!this.tds_question) { this.tds_question = new this._TDS_Question(this.tds_response_row_count); }
		//upcoming_feature: Automatically check that all used sensors are harvested.
		// This will be especially useful for GatewayQueryUtil.
		var i;
		var usedSensors = [];
		var selectArray = this.tds_question.getQuestionObj().select;

		for (i = 0; i < selectArray.length; i++) {
			//If sensor or sensor.name properties are not found, warn and continue to next loop.
			if (
				(!selectArray[i].hasOwnProperty('sensor')) ||
				(!selectArray[i].sensor.hasOwnProperty('name'))
			) {
				gs.warn('One or more select statements in TDS query contain either no ' +
					'sensor or no sensor.name property. Validation will continue but there may ' +
					'be an issue with how this select statement is formed.');
				continue;
			}

			//Add selected sensor name to the list of used sensors for return.
			usedSensors.push(selectArray[i].sensor.name);
		}

		return usedSensors;
	},

	/**
	 * DEPRECATED.
	 * @return {boolean}
	 * @private
	 */
	_checkAllSensorsAreHarvested : function () {
		if (!this.tds_question) { this.tds_question = new this._TDS_Question(this.tds_response_row_count); }
		var i;
		var missingSensors = [];
		var harvestedSensorNames = this.getAllHarvestedSensorNames();
		var usedSensors = this._getAllUsedSensors();

		//Iterate through list of all used sensors, and make sure that they're also in the list of
		// harvested sensors.
		for (i = 0; i < usedSensors.length; i++) {
			if (harvestedSensorNames.indexOf(usedSensors[i]) < 0) {
				missingSensors.push(usedSensors[i]);
			}
		}

		if (missingSensors.length > 0) {
			gs.error('One or more sensors used in the TDS question or filter are not harvested. ' +
				'This may also be caused by a sensor being harvested but deactivated. The list ' +
				'of missing sensors is as follows: \n' +
				JSON.stringify(missingSensors, null, 2));
			return false;
		}

		//If all used sensors are harvested, return true.
		return true;
	},

	/**
	 * @param questionText
	 * @return {Object|Boolean}
	 * @private
	 */
	__wip_tdsParseQuestion : function (questionText) {
		if (!this.tds_question) { this.tds_question = new this._TDS_Question(this.tds_response_row_count); }
		var responseBody;
		var rParseQuestion = this._getRESTObject('Tanium Integration Core', 'Parse Question');

		rParseQuestion.setStringParameterNoEscape('question_text', questionText);
		rParseQuestion.setStringParameterNoEscape('tanium_api_endpoint', this.TANIUM_API_ENDPOINT);

		responseBody = this._executeRESTCall(rParseQuestion);

		return responseBody;
	},

	/**
	 * Constructor for question objects.
	 * @constructor
	 * @private
	 */
	_TDS_Question : function (rowCount) {
		rowCount = (typeof rowCount == 'undefined') ? 1000 : rowCount;

		this._questionObj = {
			'row_count' : rowCount
		};


		this.getQuestionObj = function () {
			return this._questionObj;
		};

		/**
		 *
		 * @param {String} sensorName - The exact name of a Tanium sensor to return the value(s)
		 *     of.
		 * @param {boolean} [flattenResults=true] - Whether to flatten the results
		 * @param {boolean} [groupResults=true] - Whether to group the results of the sensor.
		 * @param {string} [filterOp=] - If using a filter on this sensor, specify the filter
		 *  operation (such as "Equals").
		 * This param is only required if you want to add a filter <strong>to this sensor</strong>.
		 *     This is not the same as <strong>filtering the results of this question</strong>. For
		 *     that, use the .addFilter() method of this Script Include or Class.
		 * @param {string} [filterValue=] - If using a filter on this sensor, specify the value
		 *     you're filtering for using the operation in the filterOp parameter.
		 * This param is only required if you want to add a filter <strong>to this sensor</strong>.
		 *     This is not the same as <strong>filtering the results of this question</strong>. For
		 *     that, use the .addFilter() method of this Script Include or Class.
		 */
		this.addSensor = function (
			sensorName,
			flattenResults,
			groupResults,
			filterOp,
			filterValue
		) {
			flattenResults = (typeof flattenResults == 'undefined') ? true : flattenResults;
			groupResults = (typeof groupResults == 'undefined') ? true : groupResults;

			var sensorSelectObj = {
				'sensor' : {
					'name' : sensorName
				},
				'flatten' : flattenResults,
				'group' : groupResults
			};

			//If filter operation and value have been specified, then add the sensor filter node.
			if (filterOp && filterValue) {
				sensorSelectObj.filter_values = {
					'op' : filterOp,
					'value' : filterValue
				};
			}

			//If select object doesn't yet exist, create it.
			if (!this._questionObj.hasOwnProperty('select')) {
				this._questionObj.select = [];
			}

			//Add the sensor select object into the select node of the question object.
			this._questionObj.select.push(sensorSelectObj);

			return this;
		};


		this.addFilter = function (sensorName, op, filterValue) {
			if (!sensorName || !op || !filterValue) {
				gs.error('Unable to add filter. Sensor name, operation, and filter value must ' +
					'all be specified. At least one of those arguments has not been specified, ' +
					'or has been set to a falsy value.');
				return false;
			}

			var newFilterObj = {
				'sensor' : {
					'name' : sensorName
				},
				'op' : op,
				'value' : filterValue
			};

			//If filter object does not exist, create it.
			if (!this._questionObj.hasOwnProperty('filter')) {
				this._questionObj.filter = {
					'op' : 'MatchesAll',
					'sub' : []
				};
			}

			this._questionObj.filter.sub.push(newFilterObj);

			return this;
		};

		/**
		 * Sets the filter type of the entire filter object.
		 * This does not impact the filter type of specific sensors, but rather it sets whether all
		 * filters that have been added should all be matched for a result to be returned, or
		 * whether a partial match is acceptable, etc.
		 * @param {String} filterType - The new filter type to apply to the entire query filter.
		 * upcoming_feature: Get all acceptable rows, add to the type def, and validate in
		 *  the code automatically.
		 * @returns {TaniumTDSUtil}
		 */
		this.setFilterType = function (filterType) {
			if (!this._questionObj.hasOwnProperty('filter')) {
				this._questionObj.filter = {
					'op' : filterType,
					'sub' : []
				};
			} else {
				this._questionObj.filter.op = filterType;
			}

			return this;
		};
	},

	tds_response_row_count: 10000,

	type: 'TaniumTDSUtil'
});
